public TimeSeries createCopy(RegularTimePeriod start, RegularTimePeriod end)
throws CloneNotSupportedException {

    if (start == null) {
        throw new IllegalArgumentException("Null 'start' argument.");
    }
    if (end == null) {
        throw new IllegalArgumentException("Null 'end' argument.");
    }
    if (start.compareTo(end) > 0) {
        throw new IllegalArgumentException("Requires start on or before end.");
    }

    int startIndex = getIndex(start);
    int endIndex = getIndex(end);

    // If startIndex is negative, it means start is not in the series. 
    // If so, we want to take the index of the item after the start index.
    if (startIndex < 0) {
        startIndex = -(startIndex + 1);
    }

    // If endIndex is negative, it means end is not in the series.
    // We should adjust it accordingly.
    if (endIndex < 0) {
        endIndex = -(endIndex + 1) - 1; // Get the index of the last item before the end
    }

    // Check if the start and end indices indicate a valid range
    if (startIndex > endIndex || startIndex == this.data.size()) {
        TimeSeries copy = (TimeSeries) super.clone();
        copy.data = new java.util.ArrayList();
        return copy;
    } else {
        return createCopy(startIndex, endIndex);
    }

}

