protected void burstToken(String token, boolean stopAtNonOption)
{
    for (int i = 1; i < token.length(); i++)
    {
        String ch = String.valueOf(token.charAt(i));

        if (options.hasOption(ch))
        {
            tokens.add("-" + ch);
            currentOption = options.getOption(ch);

            if (currentOption.hasArg() && (token.length() != (i + 1)))
            {
                tokens.add(token.substring(i + 1));
                break; // Only break if we have added the argument
            }
        }
        else if (stopAtNonOption)
        {
            // Process the remaining part of the token as non-option argument
            process(token.substring(i));
            break; // Stop processing further since we encountered a non-option
        }
        else
        {
            tokens.add(token);
            break; // Stop processing after adding the full token if it's not an option
        }
    }
}

