protected StringBuffer renderWrappedText(StringBuffer sb, int width, 
                                         int nextLineTabStop, String text)
{
    // Helper method to safely append remaining text without infinite loop
    final String padding = createPadding(nextLineTabStop);

    // Initial wrap position
    int pos = findWrapPos(text, width, 0);

    if (pos == -1) {
        sb.append(rtrim(text));
        return sb;
    }

    sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);

    text = padding + text.substring(pos).trim();

    while (true) {
        int prevPos = pos;
        pos = findWrapPos(text, width, 0);

        if (pos == -1) {
            sb.append(text);
            return sb;
        }

        // If wrap position doesn't advance beyond padding length, 
        // it means we can't wrap the text properly - append remainder and exit
        if (pos <= padding.length()) {
            sb.append(text.trim());
            return sb;
        }

        sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);
        // Prepare next substring with padding
        text = padding + text.substring(pos).trim();
    }
}

