protected void processProperties(Properties properties) {
    if (properties == null) {
        return;
    }

    for (Enumeration e = properties.propertyNames(); e.hasMoreElements();) {
        String option = e.nextElement().toString();

        if (!cmd.hasOption(option)) {
            Option opt = getOptions().getOption(option);
            String value = properties.getProperty(option);

            processOption(opt, value);
        }
    }
}

private void processOption(Option opt, String value) {
    if (opt.hasArg()) {
        opt.addValueForProcessing(value);
        cmd.addOption(opt);
    } else if (isTrueValue(value)) {
        cmd.addOption(opt);
    }
}

private boolean isTrueValue(String value) {
    return "yes".equalsIgnoreCase(value) || "true".equalsIgnoreCase(value) || "1".equalsIgnoreCase(value);
}

