protected int findWrapPos(String text, int width, int startPos) {
    int endPos = Math.min(startPos + width, text.length());

    // Check for newline or tab between startPos (inclusive) and endPos (exclusive)
    int newLinePos = text.indexOf('\n', startPos);
    if (newLinePos != -1 && newLinePos < endPos) {
        return newLinePos;
    }

    int tabPos = text.indexOf('\t', startPos);
    if (tabPos != -1 && tabPos < endPos) {
        return tabPos;
    }

    if (endPos >= text.length()) {
        return -1;
    }

    // Search backwards from endPos -1 to startPos for whitespace or line break
    for (int pos = endPos - 1; pos >= startPos; pos--) {
        char c = text.charAt(pos);
        if (c == ' ' || c == '\n' || c == '\r') {
            return pos;
        }
    }

    // If no whitespace found backward, just wrap at endPos (cutting word)
    return endPos;
}

