protected StringBuffer renderWrappedText(StringBuffer sb, int width, 
                                         int nextLineTabStop, String text) {
    int pos = findWrapPos(text, width, 0);

    if (pos == -1) {
        sb.append(rtrim(text));
        return sb;
    }

    sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);

    // All following lines must be padded with nextLineTabStop space characters
    final String padding = createPadding(nextLineTabStop);

    // Update text to the remaining part after the first wrapped line
    text = text.substring(pos).trim();

    while (!text.isEmpty()) { // Continue while there's text left to process
        text = padding + text;  // Prepend padding 

        pos = findWrapPos(text, width, 0); // Find new wrap position

        if (pos == -1) {
            sb.append(text);  // Append the remaining text if no further wrap position
            return sb;
        }

        sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);

        // Update text to the remaining part after the current wrapped line
        text = text.substring(pos).trim();
    }

    return sb;
}

