private boolean isSafeReplacement(Node node, Node replacement) {
    // No checks are needed for simple names.
    if (node.isName()) {
        return true;
    }

    Preconditions.checkArgument(node.isGetProp());

    // Check each child, whether it represents a name being replaced 
    return isSafeForChild(node.getFirstChild(), replacement);
}

private boolean isSafeForChild(Node child, Node replacement) {
    // Iterate over children of the 'get' property node.
    for (Node current = child; current != null; current = current.getNext()) {
        if (current.isName()) {
            // If this child's name is assigned and we're replacing it
