    if (!type.isConstructor() && !type.isEmptyType() && !type.isUnknownType()) {
        report(t, n, NOT_A_CONSTRUCTOR);
        ensureTyped(t, n);
        return; // Early exit if type is neither a constructor nor valid
    }

    // Proceed to handle function type
    FunctionType fnType = type.toMaybeFunctionType();
    if (fnType == null || !fnType.isConstructor()) {
        ensureTyped(t, n); // Ensure typed if fnType is invalid
        return; // Early exit since fnType is not a valid constructor
    }

    // Valid constructor path
    visitParameterList(t, n, fnType);
    ensureTyped(t, n, fnType.getInstanceType());
}

