// Helper method to determine if a call is a free call
private boolean isFreeCall(Node first) {
    return !NodeUtil.isGet(first) && !first.isCast();
}

// Helper method to check for direct eval
private boolean isDirectEval(Node first) {
    return first.isName() && "eval".equals(first.getString());
}

