    // Also records the deleted property so future accesses fail inlining.
    // Returns true if inlining should be aborted for this reference.
    for (Reference ref : refs) {
        Node name = ref.getNode();
        Node parent = ref.getParent();
        Node grandparent = ref.getGrandparent();

        // Handle property accesses specifically
        if (parent.isGetProp()) {
            Preconditions.checkState(parent.getFirstChild() == name);

            // Bail out if this property is being used as 'this' in a call
            if (grandparent.isCall() && grandparent.getFirstChild() == parent) {
                return false;
            }

            String propName = parent.getLastChild().getString();

            // If this property was deleted earlier, cannot inline
            if (deletedProps.contains(propName)) {
                return false;
            }

            // Detect property deletion and record it
            if (grandparent.isDelProp() && grandparent.getFirstChild() == parent) {
                deletedProps.add(propName);
                // Since deletion semantics differ, fail inlining immediately
                return false;
            }

            // Accept this property only if it's from a var or simple assignment LHS
            if (!validProps.contains(propName)) {
                if (NodeUtil.isVarOrSimpleAssignLhs(parent, grandparent)) {
                    validProps.add(propName);
                } else {
                    return false;
                }
            }

            continue; // Skip further checks for this reference
        }

        // For non-property cases, check that this is a var or assignment LHS
        if (!isVarOrAssignExprLhs(name)) {
            return false;
        }

        // Check the assigned value for this reference
        Node val = ref.getAssignedValue();
        if (val == null) {
            // Variable declared but not assigned, skip
            continue;
        }

        // Only object literal assignments can be inlined
        if (!val.isObjectLit()) {
            return false;
        }

        // Inspect each property in the object literal
        for (Node prop = val.getFirstChild(); prop != null; prop = prop.getNext()) {
            // ES5 getters/setters are not supported
            if (prop.isGetterDef() || prop.isSetterDef()) {
                return false;
            }

            String propName = prop.getString();
            validProps.add(propName);

            Node propVal = prop.getFirstChild();

            // Check for self-referential assignments via nested references
            for (Reference candidateRef : refs) {
                Node candidateParent = candidateRef.getParent();
                while (candidateParent != null && !NodeUtil.isStatementBlock(candidateParent)) {
                    if (candidateParent == propVal) {
                        // Found self-reference, inlining disallowed
                        return false;
                    }
                    candidateParent = candidateParent.getParent();
                }
            }
        }

        // This ref corresponds to a suitable object literal assignment
        canInline = true;
    }

    return canInline;
}

