private String format(JSError error, boolean warning) {
    // Get the source excerpt with better null handling
    SourceExcerptProvider sourceProvider = getSource();
    String sourceExcerpt = (sourceProvider != null) ? 
        sourceProvider.getSourceLine(error.sourceName, error.lineNumber) : null;

    // Use StringBuilder for efficient string construction
    StringBuilder result = new StringBuilder();

    // Add error location information if available
    appendErrorLocation(result, error);

    // Append the error level and description
    appendErrorMessage(result, warning, error);

    // Append source excerpt and error arrow if available
    if (sourceExcerpt != null) {
        result.append(sourceExcerpt).append('\n');
        appendErrorPointer(result, sourceExcerpt, error);
    }

    return result.toString();
}

private void appendErrorLocation(StringBuilder builder, JSError error) {
    if (error.sourceName != null) {
        builder.append(error.sourceName);
        if (error.lineNumber > 0) {
            builder.append(':').append(error.lineNumber);
        }
        builder.append(": ");
    }
}

private void appendErrorMessage(StringBuilder builder, boolean warning, JSError error) {
    builder.append(getLevelName(warning ? CheckLevel.WARNING : CheckLevel.ERROR))
          .append(" - ")
          .append(error.description)
          .append('\n');
}

private void appendErrorPointer(StringBuilder builder, String sourceExcerpt, JSError error) {
    int charno = error.getCharno();

    // Ensure the character number is within valid range
    if (0 <= charno && charno <= sourceExcerpt.length()) {
        for (int i = 0; i < charno; i++) {
            char c = sourceExcerpt.charAt(i);
            builder.append(Character.isWhitespace(c) ? c : ' ');
        }
        builder.append("^\n"); // Arrow indicating the position of the error
    }
}

