static boolean isValidDefineValue(Node val, Set<String> defines) {
    switch (val.getType()) {
        case Token.STRING:
        case Token.NUMBER:
        case Token.TRUE:
        case Token.FALSE:
            return true;

        // Binary operators require validation for both children.
        case Token.BITAND:
        case Token.BITNOT:
        case Token.BITOR:
        case Token.BITXOR:
        case Token.ADD: // Supporting binary addition
        case Token.SUB: // Supporting binary subtraction
        case Token.MUL: // Supporting binary multiplication
        case Token.DIV: // Supporting binary division
        case Token.MOD: // Supporting binary modulus
            return areValidChildren(val, defines);

        // Unary operators are valid if the child is valid.
        case Token.NOT:
        case Token.NEG:
            return isValidDefineValue(val.getFirstChild(), defines);

        // Names are valid if and only if they are defines themselves.
        case Token.NAME:
        case Token.GETPROP:
            if (val.isQualifiedName()) {
                return defines.contains(val.getQualifiedName());
            }
    }
    return false;
}

// Helper method to check validity of both children for binary operations
private static boolean areValidChildren(Node val, Set<String> defines) {
    Node firstChild = val.getFirstChild();
    Node lastChild = firstChild != null ? firstChild.getNext() : null; // Get the second child
    return isValidDefineValue(firstChild, defines) && isValidDefineValue(lastChild, defines);
}

