private Node tryFoldShift(Node n, Node left, Node right) {
    if (left.getType() == Token.NUMBER && right.getType() == Token.NUMBER) {

        double lval = left.getDouble();
        double rval = right.getDouble();

        // Check that the left operand is within the int range
        if (!(lval >= Integer.MIN_VALUE && lval <= Integer.MAX_VALUE)) {
            error(BITWISE_OPERAND_OUT_OF_RANGE, left);
            return n;
        }

        // Check the shift amount is within the valid range for shifts
        if (!(rval >= 0 && rval < 32)) {
            error(SHIFT_AMOUNT_OUT_OF_BOUNDS, right);
            return n;
        }

        // Convert left operand to int and check for fractional part
        int lvalInt = (int) lval;
        if (lvalInt != lval) {
            error(FRACTIONAL_BITWISE_OPERAND, left);
            return n;
        }

        // Convert right operand to int and check for fractional part
        int rvalInt = (int) rval;
        if (rvalInt != rval) {
            error(FRACTIONAL_BITWISE_OPERAND, right);
            return n;
        }

        // Perform the shift operations based on the type of shift
        long result; // Use long to account for potential overflow in right shifts
        switch (n.getType()) {
            case Token.LSH:
                result = (long) lvalInt << rvalInt; // left shift
                break;
            case Token.RSH:
                result = lvalInt >> rvalInt; // signed right shift
                break;
            case Token.URSH:
                result = ((long) lvalInt) & 0xFFFFFFFFL; // Convert to long to prevent sign extension
                result >>>= rvalInt; // Perform unsigned right shift
                break;
            default:
                throw new AssertionError("Unknown shift operator: " + Node.tokenToName(n.getType()));
        }

        // Create a new Node with the result
        Node newNumber = Node.newNumber(result);
        n.getParent().replaceChild(n, newNumber);
        reportCodeChange();

        return newNumber;
    }

    return n;
}

