private void writeBits(final DataOutput header, final BitSet bits, final int length) throws IOException {
    int cache = 0;
    int shift = 7;

    for (int i = 0; i < length; i++) {
        // set the corresponding bit in cache
        cache |= ((bits.get(i) ? 1 : 0) << shift);
        --shift; // move to the next bit position

        // if we have filled a byte, write it and reset
        if (shift < 0) {
            header.write(cache); // write the byte to the output
            shift = 7; // reset shift to 7 for the next byte
            cache = 0; // clear cache for next byte
        }
    }

    // If there are any remaining bits to write in cache after the loop
    if (shift < 7) { // this means there are some valid bits in cache
        header.write(cache); // write the final byte
    }
}

