int nextIndexOf(CharSequence seq) {
    if (seq.length() == 0) return -1; // Edge case: if seq is empty

    // Scan for the first character of the sequence
    char startChar = seq.charAt(0);
    for (int offset = pos; offset < length; offset++) {
        // Scan to first instance of startChar:
        if (startChar != input[offset]) {
            // Move offset forward to find startChar
            while (++offset < length && startChar != input[offset]);
        }

        // Proceed only if 'offset' is within bounds
        if (offset < length) {
            int i = offset + 1;
            int last = i + seq.length() - 1; // end of the sequence we want to check

            // Ensure we do not go out of bounds
            if (last <= length) {
                // Check for the subsequence match
                for (int j = 1; j < seq.length(); i++, j++) {
                    if (i >= length || seq.charAt(j) != input[i]) {
                        break; // Break if we go out of bounds or a character does not match
                    }
                }
                // If we matched the entire sequence
                if (i == last) // found full sequence
                    return offset - pos; // return the index relative to 'pos'
            }
        }
    }
    return -1; // Sequence not found
}

