    for (Element el : elements) {
        if (!el.tag().isFormSubmittable()) continue; // contents are form listable, superset of submitable
        String name = el.attr("name");
        if (name.isEmpty()) continue;

        String type = el.attr("type");

        if ("select".equals(el.tagName())) {
            addSelectValues(data, el, name);
        } else if ("checkbox".equalsIgnoreCase(type)) {
            addCheckboxValue(data, el, name);
        } else if ("radio".equalsIgnoreCase(type)) {
            addRadioValue(data, el, name);
        } else if (!"submit".equalsIgnoreCase(type) && !"button".equalsIgnoreCase(type) && !el.hasAttr("disabled")) {
            data.add(HttpConnection.KeyVal.create(name, el.val()));
        }
    }
    return data;
}

private void addSelectValues(List<Connection.KeyVal> data, Element el, String name) {
    Elements options = el.select("option[selected]");
    boolean hasSelected = false;

    for (Element option : options) {
        data.add(HttpConnection.KeyVal.create(name, option.val()));
        hasSelected = true;
    }

    if (!hasSelected) {
        Element firstOption = el.select("option").first();
        if (firstOption != null) {
            data.add(HttpConnection.KeyVal.create(name, firstOption.val()));
        }
    }
}

