static String unescape(String string) {
    if (!string.contains("&")) {
        return string;
    }

    Matcher m = unescapePattern.matcher(string);
    StringBuffer accum = new StringBuffer(string.length());

    while (m.find()) {
        int charval = -1;
        String num = m.group(3);
        if (num != null) {
            try {
                int base = m.group(2) != null ? 16 : 10; // base 16 for hex, 10 for decimal
                charval = Integer.parseInt(num, base);
            } catch (NumberFormatException e) {
                // skip - charval remains -1
            }
        } else {
            String name = m.group(1);
            if (full.containsKey(name)) {
                charval = full.get(name);
            }
        }

        if (charval != -1 && charval <= 0xFFFF) { // Ensure charval is valid and in range
            String c = Character.toString((char) charval);
            m.appendReplacement(accum, Matcher.quoteReplacement(c));
        } else {
            m.appendReplacement(accum, Matcher.quoteReplacement(m.group(0))); // replace with original entity if not valid
        }
    }
    m.appendTail(accum);
    return accum.toString();
