private boolean inSpecificScope(String[] targetNames, String[] baseTypes, String[] extraTypes) {
    // https://html.spec.whatwg.org/multipage/parsing.html#has-an-element-in-the-specific-scope
    int bottom = stack.size() - 1;

    // Define top to be at most MaxScopeSearchDepth from the bottom
    final int searchDepth = Math.min(MaxScopeSearchDepth, bottom);    
    final int top = Math.max(0, bottom - searchDepth);  // Ensure we do not go above index 0

    // Iterate backwards from bottom to top
    for (int pos = bottom; pos >= top; pos--) {
        final String elName = stack.get(pos).nodeName();
        if (inSorted(elName, targetNames)) {
            return true;  // Found in targetNames
        }
        if (inSorted(elName, baseTypes)) {
            return false; // Found in baseTypes - stop the search
        }
        if (extraTypes != null && inSorted(elName, extraTypes)) {
            return false; // Found in extraTypes - stop the search
        }
    }
    // If we reach this point, none were found
    return false;
}

