private static boolean looksLikeUtf8(byte[] input) {
    int i = 0;
    // BOM:
    if (input.length >= 3 && (input[0] & 0xFF) == 0xEF
            && (input[1] & 0xFF) == 0xBB && (input[2] & 0xFF) == 0xBF) {
        i = 3;
    }

    int end;
    while (i < input.length) {
        int o = input[i] & 0xFF;
        if ((o & 0x80) == 0) {
            i++; // ASCII byte
            continue;
        }

        // Determine how many bytes are in this UTF-8 character
        if ((o & 0xE0) == 0xC0) {
            end = i + 1;
        } else if ((o & 0xF0) == 0xE0) {
            end = i + 2;
        } else if ((o & 0xF8) == 0xF0) {
            end = i + 3;
        } else {
            return false; // Invalid leading byte
        }

        // Check if end pointer exceeds the input array bounds
        if (end > input.length) {
            return false; // Not enough bytes for the character
        }

        // Validate continuation bytes
        for (int j = i + 1; j < end; j++) {
            o = input[j] & 0xFF; // Ensure it is treated as unsigned
            if ((o & 0xC0) != 0x80) {
                return false; // Not a valid continuation byte
            }
        }

        i = end; // Move to the next character
    }
    return true; // All checks passed
}

