public static String getNamespaceURI(Node node) {
    if (node instanceof Document) {
        node = ((Document) node).getDocumentElement();
    }

    if (!(node instanceof Element)) {
        // Cannot determine namespace URI for non-Element nodes
        return null;
    }

    Element element = (Element) node;

    String uri = element.getNamespaceURI();
    if (uri != null && !uri.isEmpty()) {
        return uri;
    }

    String prefix = getPrefix(node);
    String qname = prefix == null ? "xmlns" : "xmlns:" + prefix;

    for (Node current = node; current != null; current = current.getParentNode()) {
        if (current.getNodeType() == Node.ELEMENT_NODE) {
            Element el = (Element) current;
            if (el.hasAttribute(qname)) {
                String value = el.getAttribute(qname);
                // Per XML spec, an empty xmlns declaration means no namespace
                return value.isEmpty() ? null : value;
            }
        }
    }

    return null;
}

