private static int greatestCommonDivisor(int u, int v) {
    // Handle zero inputs explicitly
    if (u == 0) {
        return Math.abs(v);
    }
    if (v == 0) {
        return Math.abs(u);
    }

    // If either |u| or |v| is 1, gcd is 1 immediately (optimization)
    if (Math.abs(u) == 1 || Math.abs(v) == 1) {
        return 1;
    }

    // Convert u, v to negative form safely by first converting to positive
    // and then negating (avoids overflow issues), keeping logic consistent
    u = -Math.abs(u);
    v = -Math.abs(v);

    int k = 0;
    // Extract factors of 2 from both u and v simultaneously
    while ((u & 1) == 0 && (v & 1) == 0 && k < 31) {
        u >>= 1;
        v >>= 1;
        k++;
    }
    if (k == 31) {
        throw new ArithmeticException("overflow: gcd is 2^31");
    }

    // Initialize t based on the parity of u
    int t = ((u & 1) == 1) ? v : - (u >> 1);

    // Iteratively calculate gcd using Stein's binary GCD algorithm
    do {
        // Remove all factors of 2 from t
        while ((t & 1) == 0) {
            t >>= 1;
        }

        if (t > 0) {
            u = -t;
        } else {
            v = t;
        }

        t = (v - u) >> 1;
    } while (t != 0);

    // Restore the powers of two extracted initially
    return -u << k;
}

