public int translate(CharSequence input, int index, Writer out) throws IOException {
    // Protect from ArrayIndexOutOfBounds
    if (index < 0 || index + 1 >= input.length() || input.charAt(index) != '&' || input.charAt(index + 1) != '#') {
        return 0;
    }

    int start = index + 2;
    boolean isHex = false;

    if (input.charAt(start) == 'x' || input.charAt(start) == 'X') {
        start++;
        isHex = true;
    }

    int end = start;
    // Protection added to ensure we don't go out of bounds while looking for the semicolon
    while (end < input.length() && input.charAt(end) != ';') {
        end++;
    }

    // If we reached the end without finding a semicolon, return 0
    if (end >= input.length()) {
        return 0;
    }

    int entityValue;
    try {
        if (isHex) {
            entityValue = Integer.parseInt(input.subSequence(start, end).toString(), 16);
        } else {
            entityValue = Integer.parseInt(input.subSequence(start, end).toString(), 10);
        }
    } catch (NumberFormatException nfe) {
        return 0;
    }

    // Handling for characters outside the BMP (supplementary characters)
    if (entityValue >= 0x10000) {
        int surrogate = entityValue - 0x10000;
        out.write((char) (0xD800 | (surrogate >> 10))); // High surrogate
        out.write((char) (0xDC00 | (surrogate & 0x3FF))); // Low surrogate
    } else {
        out.write(entityValue);
    }

    return 2 + (end - start) + (isHex ? 1 : 0) + 1;
}

