private Calendar adjustToTimeZone(Calendar calendar, TimeZone newTimeZone) {
    // Clone the calendar to avoid modifying the original
    Calendar clonedCalendar = (Calendar) calendar.clone();

    // Capture the original time in milliseconds
    long originalTimeInMillis = clonedCalendar.getTimeInMillis();

    // Set the desired time zone
    clonedCalendar.setTimeZone(newTimeZone);

