    if (text == null || text.length() == 0 || searchList == null || 
        searchList.length == 0 || replacementList == null || replacementList.length == 0) 
    {
        return text;
    }

    // Check for recursion limit
    if (timeToLive < 0) {
        throw new IllegalStateException("TimeToLive of " + timeToLive + " is less than 0: " + text);
    }

    int searchLength = searchList.length;
    int replacementLength = replacementList.length;

    // Ensure search and replace lists have the same length
    if (searchLength != replacementLength) {
        throw new IllegalArgumentException("Search and Replace array lengths don't match: "
            + searchLength + " vs " + replacementLength);
    }

    // Track which replacements still have valid entries
    boolean[] noMoreMatchesForReplIndex = new boolean[searchLength];

    // Variables to find match indexes
    int textIndex = -1;
    int replaceIndex = -1;
    int tempIndex;

    // Find the first occurrence of any search string in the text
    for (int i = 0; i < searchLength; i++) {
        if (noMoreMatchesForReplIndex[i] || searchList[i] == null || 
            searchList[i].length() == 0 || replacementList[i] == null) 
        {
            continue;
        }
        tempIndex = text.indexOf(searchList[i]);

        // Mark if no more matches exist
        if (tempIndex == -1) {
            noMoreMatchesForReplIndex[i] = true;
        } else {
            if (textIndex == -1 || tempIndex < textIndex) {
                textIndex = tempIndex;
                replaceIndex = i;
            }
        }
    }

    // If no more matches, return the original text
    if (textIndex == -1) {
        return text;
    }

    int start = 0;
    int increase = 0;

    // Estimate buffer size by counting length differences of valid replacements
    for (int i = 0; i < searchLength; i++) {
        if (replacementList[i] != null && searchList[i] != null) {
            int greater = replacementList[i].length() - searchList[i].length();
            if (greater > 0) {
                increase += 3 * greater; // Assume 3 matches for conservative estimate
            }
        }
    }

    // Cap the increase to not exceed 20% of the original text length
    increase = Math.min(increase, text.length() / 5);

    StringBuilder buf = new StringBuilder(text.length() + increase);

    // Process replacements
    while (textIndex != -1) {
        // Append part of the text before the match
        buf.append(text, start, textIndex);

        // Append the replacement if it's not null
        if (replaceIndex != -1 && replacementList[replaceIndex] != null) {
            buf.append(replacementList[replaceIndex]);
        }

        // Move past the replaced portion
        start = textIndex + searchList[replaceIndex].length();
        textIndex = -1; // Reset for the next search
        replaceIndex = -1;

        // Find the next match
        for (int i = 0; i < searchLength; i++) {
            if (noMoreMatchesForReplIndex[i] || searchList[i] == null || 
                searchList[i].length() == 0 || replacementList[i] == null) 
            {
                continue;
            }
            tempIndex = text.indexOf(searchList[i], start);

            if (tempIndex == -1) {
                noMoreMatchesForReplIndex[i] = true;
            } else {
                if (textIndex == -1 || tempIndex < textIndex) {
                    textIndex = tempIndex;
                    replaceIndex = i;
                }
            }
        }
    }

    // Append the remainder of the text after the last match
    buf.append(text, start, text.length());

    String result = buf.toString();
    if (!repeat) {
        return result;
    }

    return replaceEach(result, searchList, replacementList, repeat, timeToLive - 1);
}

