private StringBuffer appendQuotedString(String pattern, ParsePosition pos,
        StringBuffer appendTo, boolean escapingOn) {
    if (appendTo == null) {
        return null;
    }

    int start = pos.getIndex();
    char[] chars = pattern.toCharArray();
    int lastHold = start;

    // Iterate over the pattern from the current position
    while (pos.getIndex() < pattern.length()) {
        char currentChar = chars[pos.getIndex()];

        if (isEscapedQuote(escapingOn, chars, pos.getIndex())) {
            appendEscapedQuote(appendTo, chars, lastHold, pos.getIndex());
            lastHold = pos.getIndex() + 2; // Skip the escaped quote
            pos.setIndex(pos.getIndex() + 2); // Move past the escaped sequence
            continue;
        }

        if (currentChar == QUOTE) {
            // Append the content leading up to the quote
            appendTo.append(chars, lastHold, pos.getIndex() - lastHold);
            next(pos); // Move past the quote
            return appendTo.append(QUOTE);
        }

        next(pos);
    }

    throw new IllegalArgumentException("Unterminated quoted string at position " + start);
}

// Check if the current character and the next one form an escaped quote.
private boolean isEscapedQuote(boolean escapingOn, char[] chars, int index) {
    return escapingOn && index < chars.length - 1 && chars[index] == '\\' && chars[index + 1] == QUOTE;
