public int indexOf(String str, int startIndex) {
    if (str == null) {
        return -1; // Return -1 if the input string is null
    }

    // Ensure valid startIndex
    if (startIndex < 0) {
        startIndex = 0;
    }
    if (startIndex >= size) {
        return -1; // If startIndex exceeds the size, return -1
    }

    int strLen = str.length();
    if (strLen == 0) {
        return startIndex; // If str is empty, return startIndex
    }

    // Only proceed if there is enough space to search for str
    if (startIndex + strLen > size) {
        return -1; // If the substring can't fit in the buffer, return -1
    }

    return findSubstring(str, startIndex, strLen);
}

private int findSubstring(String str, int startIndex, int strLen) {
    char[] thisBuf = buffer; // Assuming buffer is a member variable
    int maxSearchIndex = size - strLen;

    for (int i = startIndex; i <= maxSearchIndex; i++) { 
        // Compare the characters in the buffer with the target string
        if (matchesSubstring(thisBuf, str, i, strLen)) {
            return i; // Found the substring, return the starting index
        }
    }
    return -1; // No match found
}

private boolean matchesSubstring(char[] buf, String str, int index, int strLen) {
    for (int j = 0; j < strLen; j++) {
        if (buf[index + j] != str.charAt(j)) {
            return false; // Mismatch found
        }
    }
    return true; // All characters matched
}

