    double sHighPrev = prodHigh[0];
    double sLowSum = 0;

    if (len > 1) {
        for (int i = 1; i < len; i++) {
            double prodHighNext = prodHigh[i];
            double sHighCur = sHighPrev + prodHighNext;
            double sPrime = sHighCur - prodHighNext;
            sLowSum += (prodHighNext - (sHighCur - sPrime)) + (sHighPrev - sPrime);
            sHighPrev = sHighCur;
