private double calculateAsymptoticPValue(final double Umin,
                                         final int n1,
                                         final int n2)
        throws ConvergenceException, MaxCountExceededException {

    // Changing to double to prevent overflow
    final double n1n2prod = (double) n1 * n2; 

    // Calculate expected value (mean) and variance for U
    final double EU = n1n2prod / 2.0;
    final double VarU = n1n2prod * (n1 + n2 + 1) / 12.0;

    // Check if variance is greater than zero to avoid negative or zero variance issues
    if (VarU <= 0) {
        throw new IllegalArgumentException("Variance must be greater than zero.");
    }

    // Calculate the z-score
    final double z = (Umin - EU) / FastMath.sqrt(VarU);

    // Create a standard normal distribution object
    final NormalDistribution standardNormal = new NormalDistribution(0, 1);

    // Get the cumulative probability
    double pValue = 2 * standardNormal.cumulativeProbability(z);

    // Ensure p-value is between 0 and 1
    if (pValue < 0 || pValue > 1) {
        throw new IllegalArgumentException("P-value must be between 0 and 1");
    }

    return pValue;
}

