public double cumulativeProbability(double x) throws MathException {
    // First, handle the edge cases for infinity
    if (x == Double.POSITIVE_INFINITY) {
        return 1.0;
    }
    if (x == Double.NEGATIVE_INFINITY) {
        return 0.0;
    }

    // Handle the case where the standard deviation is zero
    if (standardDeviation == 0) {
        return (x < mean) ? 0.0 : 1.0;
    }

    // Calculate the deviation
    double dev = x - mean;

    // Check for extreme z-scores and handle them efficiently
    if (dev < -20 * standardDeviation) {
        return 0.0; // Approximating the tail on the left
    }
    if (dev > 20 * standardDeviation) {
        return 1.0; // Approximating the tail on the right
    }

    // Perform the calculation using the error function
    try {
        return 0.5 * (1.0 + Erf.erf(dev / (standardDeviation * Math.sqrt(2.0))));
    } catch (MaxIterationsExceededException e) {
        // Although we expect this not to happen due to previous checks, we can handle it gracefully
        throw new MathException("Convergence error in calculation: " + e.getMessage(), e);
    }
}

