public double solve(final UnivariateRealFunction f,
                    final double min, final double max, final double initial)
        throws MaxIterationsExceededException, FunctionEvaluationException {

    clearResult();
    verifySequence(min, initial, max);

    // Return the root if the initial guess is sufficiently close
    if (isRootCloseEnough(f.value(initial))) {
        setResult(initial, 0);
        return initial;
    }

    // Check if the minimum endpoint is a root
    double yMin = f.value(min);
    if (isRootCloseEnough(yMin)) {
        setResult(min, 0);
        return min;
    }

    // Check if the maximum endpoint is a root
    double yMax = f.value(max);
    if (isRootCloseEnough(yMax)) {
        setResult(max, 0);
        return max;
    }

    // Reduce interval if min and initial bracket the root
    if (yMin * f.value(initial) < 0) {
        return solve(f, min, yMin, initial, f.value(initial), min, yMin);
    }

    // Reduce interval if initial and max bracket the root
    if (f.value(initial) * yMax < 0) {
        return solve(f, initial, f.value(initial), max, yMax, initial, f.value(initial));
    }

    // Check for non-bracketing situation
    if (yMin * yMax > 0) {
        throw MathRuntimeException.createIllegalArgumentException(
              NON_BRACKETING_MESSAGE, min, max, yMin, yMax);
    }

    // Full Brent algorithm starting with provided initial guess
    return solve(f, min, yMin, max, yMax, initial, f.value(initial));
}

// Helper method to determine if a function value is close enough to zero
private boolean isRootCloseEnough(double value) {
    return Math.abs(value) <= functionValueAccuracy;
}

