public static long safeMultiply(long val1, int val2) {
    // Handle special cases for val2
    switch (val2) {
        case 0:
            return 0L; // Multiplication by 0
        case 1:
            return val1; // Multiplication by 1
        case -1:
            if (val1 == Long.MIN_VALUE) {
                throw new ArithmeticException("Multiplication overflows a long: " + val1 + " * " + val2);
            }
            return -val1; // Negation that does not overflow
    }

    // Check for potential overflow conditions
    if (val2 > 0) { // Positive val2
        if (val1 > Long.MAX_VALUE / val2 || val1 < Long.MIN_VALUE / val2) {
            throw new ArithmeticException("Multiplication overflows a long: " + val1 + " * " + val2);
        }
    } else { // Negative val2
        if (val1 > 0 && val2 < -1 * (Long.MAX_VALUE / val1)) {
            throw new ArithmeticException("Multiplication overflows a long: " + val1 + " * " + val2);
        } else if (val1 < 0 && val2 < -1 * (Long.MIN_VALUE / val1)) {
            throw new ArithmeticException("Multiplication overflows a long: " + val1 + " * " + val2);
        }
    }

    return val1 * val2; // Safe to perform multiplication
}

